'use client';

import { useState } from 'react';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from 'recharts';

const data = [
  { month: 'Jan', allocated: 45, completed: 32, pending: 13, lagging: 5 },
  { month: 'Feb', allocated: 52, completed: 38, pending: 14, lagging: 6 },
  { month: 'Mar', allocated: 48, completed: 42, pending: 6, lagging: 3 },
  { month: 'Apr', allocated: 60, completed: 45, pending: 15, lagging: 8 },
  { month: 'May', allocated: 55, completed: 48, pending: 7, lagging: 4 },
  { month: 'Jun', allocated: 65, completed: 52, pending: 13, lagging: 7 },
];

export default function TaskOverviewChart() {
  return (
    <div className="h-80">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-lg font-semibold">Task Overview</h2>
        <select className="border rounded-lg px-3 py-1 text-sm">
          <option>Last 6 Months</option>
          <option>This Year</option>
          <option>Last Year</option>
        </select>
      </div>

      <ResponsiveContainer width="100%" height="100%">
        <BarChart data={data}>
          <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" />
          <XAxis dataKey="month" />
          <YAxis />
          <Tooltip
            contentStyle={{
              backgroundColor: 'white',
              border: '1px solid #e5e7eb',
              borderRadius: '8px',
              boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
            }}
          />
          <Legend />
          <Bar dataKey="allocated" fill="#6366f1" name="Allocated" radius={[4, 4, 0, 0]} />
          <Bar dataKey="completed" fill="#10b981" name="Completed" radius={[4, 4, 0, 0]} />
          <Bar dataKey="pending" fill="#f59e0b" name="Pending" radius={[4, 4, 0, 0]} />
          <Bar dataKey="lagging" fill="#ef4444" name="Lagging" radius={[4, 4, 0, 0]} />
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
}